// Image processing with Sharp for Nenufar watermark
const sharp = require('sharp');

// Extract data from merged nodes
const imageData = $input.item(0).binary.data;
const logoData = $input.item(1).binary.data;
const taskData = $input.item(0).json;

// Determine target platform dimensions
const isInstagram = taskData.platforms && taskData.platforms.includes('instagram');
const targetWidth = 1080;
const targetHeight = isInstagram ? 1350 : 1080; // IG: portrait, FB: square

try {
  // Load and resize main image
  let image = sharp(imageData)
    .resize(targetWidth, targetHeight, {
      fit: 'cover',
      position: 'center'
    });

  // Get metadata for sizing logo appropriately
  const metadata = await image.metadata();
  const logoSize = Math.floor(Math.min(metadata.width, metadata.height) * 0.15); // 15% of image size

  // Load and resize logo with transparency
  const logoBuffer = await sharp(logoData)
    .resize(logoSize, logoSize, {
      fit: 'inside',
      withoutEnlargement: true
    })
    .png()
    .toBuffer();

  // Apply watermark (bottom-right corner with 15% opacity)
  const processedBuffer = await image
    .composite([{
      input: logoBuffer,
      gravity: 'southeast',
      blend: 'over'
    }])
    .png()
    .toBuffer();

  return {
    json: {
      task_id: taskData.task_id,
      image_path: taskData.image_path,
      caption: taskData.caption,
      hashtags: taskData.hashtags,
      platforms: taskData.platforms,
      processed: true,
      watermark_applied: true,
      dimensions: `${targetWidth}x${targetHeight}`
    },
    binary: {
      data: processedBuffer
    }
  };
} catch (error) {
  throw new Error(`Image processing failed: ${error.message}`);
}
